var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"그럼 여러분! 오래 기다리셨죠?","JPN":"みなさま！　大変お待たせしました！","ENG":"Now, everyone, thank you for your patience.","TWN":"讓大家久等了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"지금 아카데미 운동회는 수많은 드론을 통해 스타디움의 전광판에 실시간으로 중계 중!","JPN":"只今アカデミー運動会は複数のドローンでスタジアムの電光掲示板にリアルタイムで中継中！","ENG":"The Academy's Field Day is being broadcast on the stadium's big screen in real time through numerous drones.","TWN":"現在學院運動會正通過大量無人機在體育場大螢幕上即時轉播！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"이제 곧 드디어 마지막 경기가 시작됩니다!","JPN":"いよいよ最後の試合が始まります！","ENG":"Soon, the last game will begin.","TWN":"接下來馬上就要開始最後一場比賽了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"그럼 어떤 선수들이 상위권에 올랐는지 소개해 드릴게요!","JPN":"それでは、どの選手が上位に上がってきたのか紹介します！","ENG":"Let me introduce you to the top players of the day.","TWN":"都有哪些選手成功晉級了呢？下面由我來為大家介紹一下！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"<color=#ffd34c>먼저 압도적인 점수차로 1등을 차지한! 청팀의 서윤 선수!</color>","JPN":"<color=#ffd34c>まずは圧倒的な点差で1位となっている、青組のアオイ選手！</color>","ENG":"<color=#ffd34c>First, she's got an overwhelming lead over the second place competitor. Seo Yoon of the Blue Team!</color>","TWN":"<color=#ffd34c>首先以壓倒性的分數優勢排在第一名的是！藍隊的徐芸選手！</color>"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"<color=#ffd34c>그 뒤를 바짝 쫓는 2등의......</color>","JPN":"<color=#ffd34c>その後を追う2位の……</color>","ENG":"<color=#ffd34c>And the runner up right behind her is.....</color>","TWN":"<color=#ffd34c>緊隨其後排在第二位的是……</color>"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_SPORTS","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......스카이.","JPN":"……スカイ。","ENG":"... Sky.","TWN":"……絲凱。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"어라? 방금 그 이름...... 누구지?","JPN":"あれ？　今の名前……誰だっけ？","ENG":"Huh? What's that name... I just said?","TWN":"咦？剛剛那個名字……是誰來著？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"앗차! 까먹고 있었네! 그 녀석 또 어디로 사라진 거야?!","JPN":"あっ！　忘れてた！　あいつまたどこに消えたんだ？！","ENG":"Oops! I completely forgot! Where did she go this time?","TWN":"啊！我都給忘了！那傢伙又跑哪兒去了？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그 녀석이라니?","JPN":"あいつって？","ENG":"She?","TWN":"那傢伙？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"더듬이 말이야! 뭘 모른 척 하고 그래?","JPN":"アホ毛ちゃんだよ！　知っているでしょ？","ENG":"Antenna! Don't pretend you don't know her!","TWN":"小觸角啊！你幹嘛裝得好像什麼不知道似的？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"더듬이......? 그게 누군데?","JPN":"アホ毛ちゃん……？　それって誰？","ENG":"Antenna? Who's that?","TWN":"小觸角……？那是誰啊？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"뭐야, 너? 그걸 몰라서 물어?","JPN":"え？　本当に知らないの？","ENG":"What's with you? You really don't know?","TWN":"啊，你？你不知道？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"대체 무슨 말이야......?","JPN":"何を言っているの……？","ENG":"What are you talking about?","TWN":"你究竟在說什麼……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"하아...... 처음부터 설명해 줄 테니까 잘 들어.","JPN":"はぁ·……最初から説明するからよく聞いて。","ENG":"*Sigh* Okay, listen carefully. I'll explain it from the beginning.","TWN":"哈啊……那我從頭跟你說，你聽好了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"꽃꽂이부가 부원수 미달로 폐부됐을 때 기억나?","JPN":"華道部が部員数未達で廃部になった時を覚えてる？","ENG":"Remember when the flower arranging club closed because nobody joined?","TWN":"你還記得插花部因為部員人數不足而關閉的事嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"응......","JPN":"うん……","ENG":"Yes...","TWN":"嗯……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그 뒤에 넌 다른 애들이랑 잘 못 지냈잖아.","JPN":"あの後、君は他の子たちとあまりうまくいかなかったでしょ。","ENG":"After that, you didn't get along with other kids.","TWN":"後來你跟別的同學處不來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"원래 애들이랑 노는 것보다 식물을 가꾸는 걸 더 좋아했으니까.","JPN":"元々、みんなと遊ぶよりも植物を育てるのが好きだったから。","ENG":"Because you preferred growing plants to playing with other students.","TWN":"因為比起跟同學們一起玩，你更喜歡擺弄植物。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그런데 한참을 혼자 지내던 네가 갑자기 스카이란 애를 데려왔어.","JPN":"なのに、しばらくずっと一人で過ごしていた君が、突然スカイという子を連れてきたんだ。","ENG":"So you were keeping to yourself for a while. Then, one day, you brought a girl named Sky.","TWN":"不過你自己一個人玩了很長時間之後，突然帶過來一個叫絲凱的朋友。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"자기 능력 때문에 외톨이가 됐으니까 도와달라고 말이야.","JPN":"能力のせいで一人ぼっちになったから助けてほしいと。","ENG":"You asked me to help her, because she was all alone because of her ability.","TWN":"你說她因為自己的能力落單了，所以讓我幫幫她。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"내가 보기에 너희 둘은 똑같아.","JPN":"ぼくが思うに、君たち二人は同じだよ。","ENG":"The way I see it, you two are the same.","TWN":"在我看來，你們兩個都一樣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"스카이는 다른 사람들한테 안 보이고, 넌 다른 사람을 안 보니까.","JPN":"スカイは他の人に見えないし、君は他の人を見ないから。","ENG":"Sky can't be seen by anyone, and you won't see anyone.","TWN":"絲凱是不被別人看見，你是不看別人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그런 너희 둘이라면, 분명 친구가 될 수 있다고 생각해.","JPN":"そんな君たち二人なら、きっと友達になれると思う。","ENG":"I think you two will make good friends. I really do.","TWN":"我感覺你們兩個一定能成為朋友。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"스카이도 너도, 외톨이가 되는 게 어떤 기분인지 알고 있잖아.","JPN":"スカイも君も、一人ぼっちになるのがどんな気持ちなのかよくわかるでしょ。","ENG":"Because you both know what it feels like to be alone.","TWN":"因為絲凱和你，都很清楚孤單一人是什麼心情。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그런 네가 스카이를 잊어 버린다니 말이 돼?","JPN":"そんな君がスカイを忘れるなんて、おかしくない？","ENG":"And you're saying you don't remember her? How's that possible?","TWN":"這樣的你忘了絲凱，你覺得這像話嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"지금 네가 안고 있는 꽃다발도 스카이가 만들어 준 거 아냐?","JPN":"今、君が抱いている花束もスカイが作ったものでしょ？","ENG":"Wasn't it Sky who gave you that bouquet?","TWN":"現在你抱著捧花也是絲凱給你做的不是嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......꽃다발.","JPN":"……花束。","ENG":"The bouquet.","TWN":"……捧花。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"이거, 받아 줄래?","JPN":"これ、受け取ってくれる？","ENG":"Here, will you take this?","TWN":"這個，你願意收下嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"아르티한테 네가 꽃을 좋아한다고 들어서 꽃다발을 만들었어.","JPN":"アルティからケイシーは花が好きと聞いて花束を作ったの。","ENG":"Arti told me you like flowers, so I made you a bouquet.","TWN":"我聽阿爾蒂說你喜歡花，所以做了一個花束。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"블루로즈야. 이 섬에서만 피는 꽃이래.","JPN":"ブルーローズだよ。この島でしか咲かない花なんだって。","ENG":"They're blue roses. They grow only on this island.","TWN":"是藍玫瑰，聽說只有這個島上才有。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"분명 너한테 잘 어울릴 거야.","JPN":"きっとケイシーに似合うと思う。","ENG":"I'm sure they will go well with you.","TWN":"一定很適合你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"스카이 레이필드!","JPN":"スカイ・レイフィールド！","ENG":"Sky Layfield!","TWN":"絲凱·蕾菲爾德！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"고마워, 아르티! 난 스카이를 찾으러 갈래!","JPN":"ありがとう、アルティ！　あたしはスカイを探しに行く！","ENG":"Thanks, Arti! Now I'll go find her!","TWN":"謝謝你，阿爾蒂！我要去找絲凱！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"어? 그, 그래!","JPN":"え？　あ、うん！","ENG":"Huh? O-okay!","TWN":"啊？好，好的！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"......그런데 스카이가 누구야?","JPN":"……ところでスカイって誰？","ENG":"But who's Sky?","TWN":"……不過絲凱是誰啊？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"설명할 시간 없어! 나 먼저 갈게!","JPN":"説明する時間がない！　あたしは先に行く！","ENG":"I don't have time to explain! I'll go now!","TWN":"沒時間跟你解釋了！我先走了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"케, 케이시! 같이 가!","JPN":"ケ、ケイシー！　一緒に行こう！","ENG":"K-Kaci! Wait, I'll go with you!","TWN":"凱，卡西！你等等我！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"자! 최후의 최후! 이제 영광의 고지가 코앞입니다!","JPN":"さあ！　最後の最後！　栄光の扉は目の前にある！","ENG":"Now, we're so close to the end! The hill of glory is right before our eyes!","TWN":"好啦！最後的最後！榮耀已經近在眼前了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L10_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"눈앞에 숨겨진 우승상품의 주인은 누가 될 것인가!","JPN":"願い玉を手に入れる者は誰になるのでしょうか？","ENG":"Who's going to find the winning prize that's hidden under our noses?","TWN":"藏在眼前的冠軍獎品將落入何人之手！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"그럼 다들 마지막까지 최선을 다해 주세요!","JPN":"最後まで最善を尽くしてください！","ENG":"Everyone, please do your best until the end!","TWN":"大家全力以赴地拼搏到最後吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_NULL","text":{"KOREA":"경기, 시작!","JPN":"試合、スタート！","ENG":"Let's start the game!","TWN":"比賽，開始！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};